local function uq(oZ,nx,...)
    if not nx then
        local oq=...
        error(debug.traceback(oZ,oq),2)
    end
    if coroutine.status(oZ)~="dead" then
        error(debug.traceback(oZ,"Attempted to yield inside changed event!"),2)
    end
    return ...
end
local function ur(da,...)
    local oZ=coroutine.create(da)
    return uq(oZ,coroutine.resume(oZ,...))
end
return ur
